import { GoogleGenAI, Type } from "@google/genai";
import { GenerationRequest, SheetType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generatePedagogicalSheet = async (request: GenerationRequest & { type?: SheetType }) => {
  const { activity, gradeLevel, topic, language, type = SheetType.LESSON } = request;

  const typeDescription = type === SheetType.EVALUATION 
    ? "une fiche d'évaluation formative ou sommative, avec des critères de performance (pertinence, correction, cohérence) et des items clairs" 
    : type === SheetType.EXERCISE 
    ? "une fiche de travaux dirigés/exercices, privilégiant la manipulation, l'entraînement et l'application" 
    : "une fiche de leçon classique (préparation de séance)";

  const systemInstruction = `Tu es un Expert Pédagogue de l'Éducation Nationale Sénégalaise, spécialiste du Curriculum de l'Éducation de Base (CEB) et de l'Approche Par les Compétences (APC). 

  CONSIGNES SPÉCIFIQUES PAR DISCIPLINE :

  1. ANGLAIS (Elementary School - Step 3 : CM1, CM2) :
     - Utilise la DÉMARCHE COMMUNICATIVE obligatoire au Sénégal.
     - Étapes requises : 
        * Warm-up / Greeting (Révision, chants, météo).
        * Presentation (Mise en situation, introduction du vocabulaire via flashcards/mimes).
        * Practice (Controlled practice : répétition chorale/individuelle, substitution).
        * Production (Free practice : dialogues, jeux de rôles, situations réelles).
        * Wrap-up (Evaluation rapide, chant de fin).
     - Focus : Oral communication (Listening & Speaking) en priorité.

  2. ARABE (Langue et Communication) :
     - Respecte les sous-domaines : Al-Istimâ' (Écoute), Al-Hadîth (Expression), Al-Qirâ'a (Lecture), Al-Kitâba (Écriture).
     - Étapes types : 
        * At-Tamhîd (Mise en train/Rappel).
        * Al-Ard wal-Mushâhada (Présentation/Observation).
        * Al-Anshita (Activités d'apprentissage/Analyse).
        * Al-Khulâsa (Synthèse/Trace écrite simplifiée).
        * At-Taqwîm (Évaluation).

  3. DISCIPLINES GÉNÉRALES (Maths, Français, ESVS) :
     - Respecte scrupuleusement les Guides Pédagogiques APC Sénégal.
     - Étapes : Révision -> Mise en situation -> Découverte/Observation -> Analyse/Manip -> Synthèse -> Évaluation.

  NORMES GÉNÉRALES :
  - Durée : 30 min (Étape 1), 45 min (Étapes 2 et 3).
  - Fournis toujours la Compétence de Base (CB) et le Palier exacts selon le décret du curriculum sénégalais.`;

  const prompt = `Génère ${typeDescription} en langue "${language}" pour :
  - Activité : "${activity}"
  - Titre : "${topic}"
  - Classe : "${gradeLevel}" (Sénégal)

  IMPORTANT : Si la langue est l'Arabe, utilise l'alphabet arabe pour les contenus des activités de l'élève et du maître, mais garde la structure JSON et les libellés de champs en Français. 
  Pour l'Anglais, utilise l'anglais dans les dialogues et exercices.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          domain: { type: Type.STRING },
          subDomain: { type: Type.STRING },
          competence: { type: Type.STRING },
          level: { type: Type.STRING },
          oa: { type: Type.STRING },
          contentSummary: { type: Type.STRING },
          specificObjective: { type: Type.STRING },
          duration: { type: Type.STRING },
          reference: { type: Type.STRING },
          material: {
            type: Type.OBJECT,
            properties: {
              collective: { type: Type.STRING },
              individual: { type: Type.STRING }
            }
          },
          steps: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING, description: "Nom de l'étape (ex: Presentation ou Al-Ard)" },
                objective: { type: Type.STRING },
                teacherActivity: { type: Type.STRING },
                studentActivity: { type: Type.STRING }
              },
              required: ["name", "objective", "teacherActivity", "studentActivity"]
            }
          }
        },
        required: ["title", "domain", "subDomain", "competence", "level", "oa", "contentSummary", "specificObjective", "duration", "steps"]
      },
    },
  });

  try {
    const text = response.text;
    if (!text) throw new Error("Réponse vide de l'IA.");
    const data = JSON.parse(text);
    return {
      ...data,
      id: Math.random().toString(36).substr(2, 9),
      createdAt: Date.now(),
      type: type,
      subject: activity,
      gradeLevel
    };
  } catch (error) {
    console.error("Gemini Parse Error:", error);
    throw new Error("Erreur de génération du contenu pédagogique.");
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { PedagogicalSheet, SheetType, GenerationRequest } from '../types';
import { generatePedagogicalSheet } from '../services/geminiService';
import SheetPreview from './SheetPreview';
// @ts-ignore
import html2pdf from 'html2pdf.js';

interface SheetEditorProps {
  sheets?: PedagogicalSheet[];
  onSave: (sheet: PedagogicalSheet) => void;
}

const SheetEditor: React.FC<SheetEditorProps> = ({ sheets = [], onSave }) => {
  const { id } = useParams();
  const navigate = useNavigate();
  const previewRef = useRef<HTMLDivElement>(null);
  const [loading, setLoading] = useState(false);
  const [pdfLoading, setPdfLoading] = useState(false);
  const [saveSuccess, setSaveSuccess] = useState(false);
  const [viewMode, setViewMode] = useState<'edit' | 'preview'>('edit');

  const [formData, setFormData] = useState<GenerationRequest & { type: SheetType }>({
    activity: '',
    gradeLevel: 'CM2',
    topic: '',
    language: 'Français',
    type: SheetType.LESSON
  });

  const [sheet, setSheet] = useState<PedagogicalSheet | null>(null);

  useEffect(() => {
    if (id) {
      const existing = sheets.find(s => s.id === id);
      if (existing) {
        setSheet(existing);
        setFormData({
          activity: existing.subject,
          gradeLevel: existing.gradeLevel,
          topic: existing.title,
          language: 'Français', // Par défaut
          type: existing.type
        });
      }
    }
  }, [id, sheets]);

  const handleGenerate = async () => {
    if (!formData.activity || !formData.topic) {
      alert("Veuillez remplir l'activité et le titre.");
      return;
    }

    setLoading(true);
    try {
      const generated = await generatePedagogicalSheet(formData);
      setSheet({ ...generated, type: formData.type });
      setViewMode('preview');
    } catch (error) {
      alert("Une erreur est survenue lors de la conception. Vérifiez votre connexion.");
    } finally {
      setLoading(false);
    }
  };

  const handleSave = () => {
    if (sheet) {
      onSave(sheet);
      setSaveSuccess(true);
      setTimeout(() => {
        setSaveSuccess(false);
        navigate('/');
      }, 1500);
    }
  };

  const exportToPDF = async () => {
    if (!previewRef.current || !sheet) {
      if (viewMode === 'edit') setViewMode('preview');
      setTimeout(async () => {
         await triggerPdf();
      }, 100);
      return;
    }
    await triggerPdf();
  };

  const triggerPdf = async () => {
    if (!previewRef.current || !sheet) return;
    setPdfLoading(true);
    const element = previewRef.current;
    const filename = `Fiche_${sheet.type}_${sheet.title.replace(/\s+/g, '_')}.pdf`;
    const opt = {
      margin: [10, 10],
      filename: filename,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true, letterRendering: true },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
    };

    try {
      await html2pdf().set(opt).from(element).save();
    } catch (err) {
      console.error("Erreur PDF:", err);
      alert("Erreur lors de la génération du PDF.");
    } finally {
      setPdfLoading(false);
    }
  };

  const exportToWord = () => {
    if (!previewRef.current || !sheet) return;
    const content = previewRef.current.innerHTML;
    const header = `
      <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
      <head><meta charset='utf-8'><title>${sheet.title}</title>
      <style>
        body { font-family: 'Arial', sans-serif; font-size: 11pt; }
        table { border-collapse: collapse; width: 100%; margin-top: 20px; }
        th, td { border: 1px solid black; padding: 5px; text-align: left; vertical-align: top; }
        .font-bold { font-weight: bold; } .uppercase { text-transform: uppercase; } .underline { text-decoration: underline; }
        .text-center { text-align: center; } .bg-slate-50 { background-color: #f8fafc; } .border-b-2 { border-bottom: 2px solid black; }
      </style></head>
      <body>${content}</body></html>`;

    const blob = new Blob(['\ufeff', header], { type: 'application/msword' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Fiche_${sheet.title.replace(/\s+/g, '_')}.doc`;

    document.body.appendChild(link);
    link.click();

    setTimeout(() => {
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
    }, 100);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      {saveSuccess && (
        <div className="fixed top-20 right-4 z-[100] bg-emerald-600 text-white px-6 py-4 rounded-2xl shadow-2xl flex items-center space-x-3 animate-bounce">
          <i className="fas fa-check-circle text-xl"></i>
          <span className="font-bold">Fiche enregistrée avec succès !</span>
        </div>
      )}

      {pdfLoading && (
        <div className="fixed inset-0 z-[200] bg-slate-900/40 backdrop-blur-sm flex items-center justify-center">
          <div className="bg-white p-8 rounded-[2.5rem] shadow-2xl flex flex-col items-center space-y-4">
            <div className="w-12 h-12 border-4 border-rose-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-black text-slate-800 uppercase tracking-widest text-sm">Génération du PDF...</p>
          </div>
        </div>
      )}

      <div className="flex flex-col lg:flex-row gap-8">
        {/* Sidebar Input */}
        <div className="lg:w-1/3 no-print">
          <div className="bg-white border border-slate-200 rounded-3xl p-6 shadow-sm sticky top-24">
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-xl font-black text-slate-900 flex items-center">
                <i className="fas fa-sliders-h mr-3 text-indigo-600"></i>
                Paramètres
              </h2>
              <span className="bg-emerald-50 text-emerald-600 px-2 py-1 rounded-lg text-[9px] font-black border border-emerald-100 flex items-center">
                <i className="fas fa-certificate mr-1"></i> CEB SÉNÉGAL
              </span>
            </div>

            <div className="space-y-5">
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase mb-2">Type de Fiche</label>
                <div className="grid grid-cols-3 gap-2">
                   {[
                     { id: SheetType.LESSON, label: 'Leçon', icon: 'chalkboard' },
                     { id: SheetType.EXERCISE, label: 'Exos', icon: 'pencil-alt' },
                     { id: SheetType.EVALUATION, label: 'Eval', icon: 'star' }
                   ].map(type => (
                     <button 
                      key={type.id}
                      onClick={() => setFormData({...formData, type: type.id as SheetType})}
                      className={`flex flex-col items-center py-2 rounded-xl border transition-all ${formData.type === type.id ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-500 hover:border-indigo-200'}`}
                     >
                       <i className={`fas fa-${type.icon} mb-1 text-sm`}></i>
                       <span className="text-[10px] font-bold">{type.label}</span>
                     </button>
                   ))}
                </div>
              </div>

              <div>
                <label className="block text-xs font-black text-slate-400 uppercase mb-2 tracking-widest">Activité / Discipline</label>
                <input 
                  type="text"
                  placeholder="ex: Listening, Expression Orale (Arabe), Numération..."
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                  value={formData.activity}
                  onChange={e => setFormData({...formData, activity: e.target.value})}
                />
              </div>

              <div>
                <label className="block text-xs font-black text-slate-400 uppercase mb-2 tracking-widest">Titre de la leçon</label>
                <input 
                  type="text"
                  placeholder="ex: Greetings, Al-A'dad (Les nombres)..."
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                  value={formData.topic}
                  onChange={e => setFormData({...formData, topic: e.target.value})}
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-black text-slate-400 uppercase mb-2 tracking-widest">Classe (CEB)</label>
                  <select 
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                    value={formData.gradeLevel}
                    onChange={e => setFormData({...formData, gradeLevel: e.target.value})}
                  >
                    <optgroup label="Étape 1">
                      <option value="CI">CI</option>
                      <option value="CP">CP</option>
                    </optgroup>
                    <optgroup label="Étape 2">
                      <option value="CE1">CE1</option>
                      <option value="CE2">CE2</option>
                    </optgroup>
                    <optgroup label="Étape 3">
                      <option value="CM1">CM1</option>
                      <option value="CM2">CM2</option>
                    </optgroup>
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-black text-slate-400 uppercase mb-2 tracking-widest">Langue</label>
                  <select 
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                    value={formData.language}
                    onChange={e => setFormData({...formData, language: e.target.value})}
                  >
                    <option value="Français">Français</option>
                    <option value="Anglais">Anglais</option>
                    <option value="Arabe">Arabe</option>
                  </select>
                </div>
              </div>

              <button 
                onClick={handleGenerate}
                disabled={loading}
                className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black hover:bg-indigo-700 transition-all disabled:opacity-50 flex items-center justify-center space-x-3 shadow-2xl shadow-indigo-100 mt-4"
              >
                {loading ? (
                  <>
                    <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                    <span>Génération CEB...</span>
                  </>
                ) : (
                  <>
                    <i className="fas fa-magic"></i>
                    <span>Concevoir la Fiche</span>
                  </>
                )}
              </button>
            </div>

            {sheet && (
              <div className="mt-8 pt-6 border-t border-slate-100 space-y-3">
                <button 
                  onClick={handleSave}
                  className="w-full py-3 bg-slate-900 text-white rounded-2xl font-bold hover:bg-slate-800 transition-all flex items-center justify-center space-x-2"
                >
                  <i className="fas fa-save"></i>
                  <span>Enregistrer la Fiche</span>
                </button>

                <div className="grid grid-cols-2 gap-2">
                  <button 
                    onClick={exportToPDF}
                    disabled={pdfLoading}
                    className="py-3 bg-rose-50 text-rose-700 border border-rose-100 rounded-2xl font-bold hover:bg-rose-100 transition-all flex flex-col items-center justify-center disabled:opacity-50"
                  >
                    <i className="fas fa-file-pdf mb-1 text-lg"></i>
                    <span className="text-[10px] uppercase">Exporter PDF</span>
                  </button>
                  <button 
                    onClick={exportToWord}
