          </div>
        </div>

        {/* View Area */}
        <div className="lg:w-2/3">
          {!sheet ? (
            <div className="bg-white border border-slate-200 rounded-[2.5rem] p-16 text-center flex flex-col items-center justify-center min-h-[600px] shadow-sm">
              <div className="w-32 h-32 bg-indigo-50 rounded-full flex items-center justify-center text-indigo-200 mb-8 animate-pulse">
