                           <div className="h-[2px] bg-slate-100 flex-grow"></div>
                        </div>
                        {sheet.steps.map((step, idx) => (
                          <div key={idx} className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm space-y-4 hover:border-indigo-100 transition-colors">
                            <div className="flex justify-between items-center">
                              <input 
                                className="font-black text-indigo-600 bg-transparent border-none focus:ring-0 uppercase text-lg w-full"
                                value={step.name}
                                onChange={e => {
                                  const newSteps = [...sheet.steps];
                                  newSteps[idx].name = e.target.value;
                                  setSheet({...sheet, steps: newSteps});
                                }}
                              />
                              <span className="text-[10px] bg-slate-100 text-slate-500 px-3 py-1 rounded-full font-black uppercase whitespace-nowrap">Phase {idx + 1}</span>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                               <div className="space-y-2">
                                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1 tracking-widest">Maître / Mudarris</label>
                                  <textarea 
                                    className="w-full bg-slate-50 border-none rounded-2xl p-4 text-xs h-32 outline-none focus:ring-2 focus:ring-indigo-500 leading-relaxed"
                                    value={step.teacherActivity}
                                    onChange={e => {
                                      const newSteps = [...sheet.steps];
                                      newSteps[idx].teacherActivity = e.target.value;
                                      setSheet({...sheet, steps: newSteps});
                                    }}
                                  />
                               </div>
                               <div className="space-y-2">
                                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1 tracking-widest">Élèves / At-Talamidh</label>
                                  <textarea 
                                    className="w-full bg-slate-50 border-none rounded-2xl p-4 text-xs h-32 outline-none focus:ring-2 focus:ring-indigo-500 leading-relaxed"
                                    value={step.studentActivity}
                                    onChange={e => {
                                      const newSteps = [...sheet.steps];
                                      newSteps[idx].studentActivity = e.target.value;
                                      setSheet({...sheet, steps: newSteps});
                                    }}
                                  />
                               </div>
                            </div>
                          </div>
                        ))}
                      </section>
                  </div>
                ) : (
                  <div ref={previewRef} className="animate-in zoom-in-95 duration-300">
                    <SheetPreview sheet={sheet} />
                  </div>
                )}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default SheetEditor;

import { GoogleGenAI, Type } from "@google/genai";
import { GenerationRequest, SheetType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generatePedagogicalSheet = async (request: GenerationRequest & { type?: SheetType }) => {
  const { activity, gradeLevel, topic, language, type = SheetType.LESSON } = request;

  const systemInstruction = `Tu es l'Expert Ultime de l'Éducation Nationale Sénégalaise, détenteur de tous les Guides Pédagogiques du Curriculum de l'Éducation de Base (CEB) pour les Étapes 1 (CI-CP), 2 (CE1-CE2) et 3 (CM1-CM2).

  TON OBJECTIF : Générer des fiches d'une précision académique irréprochable selon l'Approche Par les Compétences (APC).

  CHAMP D'ACTION (DOMAINE ET DISCIPLINES) :
  - LANGUE ET COMMUNICATION : Français (Lecture, Écrit, Communication Orale), Arabe (Al-Lugha), Anglais (Step 3).
  - MATHÉMATIQUES : Activités Numériques, Géométrie, Mesure, Résolution de Problèmes.
  - ÉSVS (Éducation à la Science et à la Vie Sociale) : Découverte du monde, Histoire, Géographie, Initiation scientifique et technologique.
  - ÉDUCATION AU DÉVELOPPEMENT DURABLE (EDD) : Vivre dans son milieu, Vivre ensemble.
  - ARTS ET SPORT : Éducation Artistique (Plastique, Musicale), EPSS (Éducation Physique, Sportive et à la Santé).

  STRUCTURE TYPE APC (À ADAPTER SELON LE CONTENU) :
  1. RÉVISION / MISE EN TRAIN : Rappel des prérequis.
  2. MISE EN SITUATION : Présentation d'une situation-problème concrète et contextualisée au Sénégal.
  3. OBSERVATION / DÉCOUVERTE : Émission d'hypothèses par les élèves.
  4. ANALYSE / MANIPULATION : Phase active de recherche (travail de groupe ou individuel).
  5. SYNTHÈSE / GÉNÉRALISATION : Co-construction de la "Trace Écrite" ou de la règle.
  6. ÉVALUATION : Vérification immédiate de l'atteinte de l'Objectif Spécifique.

  CONSIGNES DE RÉDACTION :
  - Utilise des prénoms sénégalais (Fatou, Moussa, Ami...).
  - Si la langue est l'Arabe, rédige les activités en Arabe mais garde la structure JSON en Français.
  - La "Compétence de Base" et le "Palier" doivent correspondre exactement aux textes officiels du CEB.`;

  const prompt = `Génère une fiche de type "${type}" pour la classe de "${gradeLevel}".
  Détails :
  - Activité/Discipline : "${activity}"
  - Titre de la leçon : "${topic}"
  - Langue d'enseignement : "${language}"

  Rends le contenu pratique, avec des consignes claires pour le maître et des actions concrètes pour l'élève.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          domain: { type: Type.STRING },
          subDomain: { type: Type.STRING },
          competence: { type: Type.STRING },
          level: { type: Type.STRING },
          oa: { type: Type.STRING },
          contentSummary: { type: Type.STRING },
          specificObjective: { type: Type.STRING },
          duration: { type: Type.STRING },
          reference: { type: Type.STRING },
          material: {
            type: Type.OBJECT,
            properties: {
              collective: { type: Type.STRING },
              individual: { type: Type.STRING }
            }
          },
          steps: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                objective: { type: Type.STRING },
                teacherActivity: { type: Type.STRING },
                studentActivity: { type: Type.STRING }
              },
              required: ["name", "objective", "teacherActivity", "studentActivity"]
            }
          }
        },
        required: ["title", "domain", "subDomain", "competence", "level", "oa", "contentSummary", "specificObjective", "duration", "steps"]
      },
    },
  });

  try {
    const text = response.text;
    if (!text) throw new Error("Réponse vide.");
    const data = JSON.parse(text);
    return {
      ...data,
      id: Math.random().toString(36).substr(2, 9),
      createdAt: Date.now(),
      type: type,
      subject: activity,
      gradeLevel
    };
  } catch (error) {
    console.error("Gemini Error:", error);
    throw new Error("Impossible de générer la fiche pédagogique.");
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { PedagogicalSheet, SheetType, GenerationRequest } from '../types';
import { generatePedagogicalSheet } from '../services/geminiService';
import SheetPreview from './SheetPreview';
// @ts-ignore
import html2pdf from 'html2pdf.js';

interface SheetEditorProps {
  sheets?: PedagogicalSheet[];
  onSave: (sheet: PedagogicalSheet) => void;
}

const SheetEditor: React.FC<SheetEditorProps> = ({ sheets = [], onSave }) => {
  const { id } = useParams();
  const navigate = useNavigate();
  const previewRef = useRef<HTMLDivElement>(null);
  const [loading, setLoading] = useState(false);
  const [pdfLoading, setPdfLoading] = useState(false);
  const [saveSuccess, setSaveSuccess] = useState(false);
  const [viewMode, setViewMode] = useState<'edit' | 'preview'>('edit');

  const [formData, setFormData] = useState<GenerationRequest & { type: SheetType }>({
    activity: '',
    gradeLevel: 'CM2',
    topic: '',
    language: 'Français',
    type: SheetType.LESSON
  });

  const [sheet, setSheet] = useState<PedagogicalSheet | null>(null);

  useEffect(() => {
    if (id) {
      const existing = sheets.find(s => s.id === id);
      if (existing) {
        setSheet(existing);
        setFormData({
          activity: existing.subject,
          gradeLevel: existing.gradeLevel,
          topic: existing.title,
          language: 'Français',
          type: existing.type
        });
      }
    }
  }, [id, sheets]);

  const handleGenerate = async () => {
    if (!formData.activity || !formData.topic) {
      alert("Veuillez renseigner la discipline et le titre de la leçon.");
      return;
    }

    setLoading(true);
    try {
      const generated = await generatePedagogicalSheet(formData);
      setSheet({ ...generated, type: formData.type });
      setViewMode('preview');
    } catch (error) {
      alert("Erreur lors de la génération. Réessayez.");
    } finally {
      setLoading(false);
    }
  };

  const handleSave = () => {
    if (sheet) {
      onSave(sheet);
      setSaveSuccess(true);
      setTimeout(() => {
        setSaveSuccess(false);
        navigate('/');
      }, 1500);
    }
  };

  const exportToPDF = async () => {
    if (!previewRef.current || !sheet) {
      if (viewMode === 'edit') setViewMode('preview');
      setTimeout(async () => {
         await triggerPdf();
      }, 100);
      return;
    }
    await triggerPdf();
  };

  const triggerPdf = async () => {
    if (!previewRef.current || !sheet) return;
    setPdfLoading(true);
    const element = previewRef.current;
    const opt = {
      margin: [10, 10],
      filename: `Fiche_${sheet.title}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2 },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
    };

    try {
      await html2pdf().set(opt).from(element).save();
    } catch (err) {
      alert("Erreur PDF.");
    } finally {
      setPdfLoading(false);
    }
  };

  const exportToWord = () => {
    if (!previewRef.current || !sheet) return;
    const content = previewRef.current.innerHTML;
    const header = `<html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'><head><meta charset='utf-8'><title>${sheet.title}</title><style>body { font-family: 'Arial'; } table { border-collapse: collapse; width: 100%; } th, td { border: 1px solid black; padding: 5px; }</style></head><body>${content}</body></html>`;
    const blob = new Blob(['\ufeff', header], { type: 'application/msword' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Fiche_${sheet.title}.doc`;
    link.click();
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      {saveSuccess && (
        <div className="fixed top-20 right-4 z-[100] bg-emerald-600 text-white px-6 py-4 rounded-2xl shadow-2xl flex items-center space-x-3 animate-bounce">
          <i className="fas fa-check-circle text-xl"></i>
          <span className="font-bold">Fiche enregistrée !</span>
        </div>
      )}

      {pdfLoading && (
        <div className="fixed inset-0 z-[200] bg-slate-900/40 backdrop-blur-sm flex items-center justify-center">
          <div className="bg-white p-8 rounded-[2.5rem] shadow-2xl flex flex-col items-center space-y-4">
            <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-black text-slate-800 uppercase tracking-widest text-sm">Génération du fichier...</p>
          </div>
        </div>
      )}

      <div className="flex flex-col lg:flex-row gap-8">
        <div className="lg:w-1/3 no-print">
          <div className="bg-white border border-slate-200 rounded-3xl p-6 shadow-sm sticky top-24">
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-xl font-black text-slate-900 flex items-center">
                <i className="fas fa-sliders-h mr-3 text-indigo-600"></i>
                Configuration
              </h2>
              <span className="bg-indigo-50 text-indigo-600 px-3 py-1 rounded-lg text-[10px] font-black border border-indigo-100 uppercase tracking-tighter">
                CEB Sénégal
              </span>
            </div>

            <div className="space-y-5">
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase mb-2">Type de document</label>
                <div className="grid grid-cols-3 gap-2">
                   {[
                     { id: SheetType.LESSON, label: 'Leçon', icon: 'chalkboard' },
                     { id: SheetType.EXERCISE, label: 'TD/Exos', icon: 'pencil-alt' },
                     { id: SheetType.EVALUATION, label: 'Évaluation', icon: 'star' }
                   ].map(type => (
                     <button 
                      key={type.id}
                      onClick={() => setFormData({...formData, type: type.id as SheetType})}
                      className={`flex flex-col items-center py-3 rounded-xl border transition-all ${formData.type === type.id ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-500 hover:border-indigo-200'}`}
                     >
                       <i className={`fas fa-${type.icon} mb-1 text-sm`}></i>
                       <span className="text-[10px] font-bold">{type.label}</span>
                     </button>
                   ))}
                </div>
              </div>

              <div>
                <label className="block text-xs font-black text-slate-400 uppercase mb-2 tracking-widest">Discipline / Activité</label>
                <input 
                  type="text"
                  placeholder="ex: Grammaire, Numération, Histoire..."
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 outline-none"
                  value={formData.activity}
                  onChange={e => setFormData({...formData, activity: e.target.value})}
                />
              </div>

              <div>
                <label className="block text-xs font-black text-slate-400 uppercase mb-2 tracking-widest">Titre de la leçon</label>
                <input 
                  type="text"
                  placeholder="ex: Le pluriel des noms, La multiplication..."
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 outline-none"
                  value={formData.topic}
                  onChange={e => setFormData({...formData, topic: e.target.value})}
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-black text-slate-400 uppercase mb-2 tracking-widest">Classe</label>
                  <select 
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 outline-none"
                    value={formData.gradeLevel}
                    onChange={e => setFormData({...formData, gradeLevel: e.target.value})}
                  >
                    <optgroup label="Étape 1">
                      <option value="CI">CI</option>
                      <option value="CP">CP</option>
                    </optgroup>
                    <optgroup label="Étape 2">
                      <option value="CE1">CE1</option>
                      <option value="CE2">CE2</option>
                    </optgroup>
                    <optgroup label="Étape 3">
                      <option value="CM1">CM1</option>
                      <option value="CM2">CM2</option>
                    </optgroup>
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-black text-slate-400 uppercase mb-2 tracking-widest">Langue</label>
                  <select 
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 outline-none"
                    value={formData.language}
                    onChange={e => setFormData({...formData, language: e.target.value})}
                  >
                    <option value="Français">Français</option>
                    <option value="Anglais">Anglais</option>
                    <option value="Arabe">Arabe</option>
                  </select>
                </div>
              </div>

              <button 
                onClick={handleGenerate}
                disabled={loading}
                className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black hover:bg-indigo-700 transition-all disabled:opacity-50 flex items-center justify-center space-x-3 shadow-xl shadow-indigo-100"
              >
                {loading ? (
                  <>
                    <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                    <span>Conception en cours...</span>
                  </>
                ) : (
                  <>
                    <i className="fas fa-wand-magic-sparkles"></i>
                    <span>Générer la Fiche</span>
                  </>
                )}
              </button>
            </div>

            {sheet && (
              <div className="mt-8 pt-6 border-t border-slate-100 space-y-3">
                <button onClick={handleSave} className="w-full py-3 bg-slate-900 text-white rounded-2xl font-bold hover:bg-slate-800 transition-all">
                  <i className="fas fa-save mr-2"></i> Enregistrer
                </button>
                <div className="grid grid-cols-2 gap-2">
                  <button onClick={exportToPDF} className="py-3 bg-rose-50 text-rose-700 border border-rose-100 rounded-2xl font-bold text-xs uppercase">
                    <i className="fas fa-file-pdf mb-1 block text-lg"></i> PDF
