                     </div>

                      <section className="space-y-6">
                        <h4 className="text-sm font-black text-slate-900 uppercase tracking-widest border-l-4 border-indigo-600 pl-3">Déroulement de la séance</h4>
                        {sheet.steps.map((step, idx) => (
                          <div key={idx} className="bg-slate-50 p-6 rounded-2xl space-y-4">
                            <input 
                              className="font-black text-indigo-600 bg-transparent border-none focus:ring-0 uppercase w-full"
                              value={step.name}
                              onChange={e => {
                                const newSteps = [...sheet.steps];
                                newSteps[idx].name = e.target.value;
                                setSheet({...sheet, steps: newSteps});
                              }}
                            />
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                               <div>
                                  <label className="text-[9px] font-black text-slate-400 uppercase">Activité du Maître</label>
                                  <textarea 
                                    className="w-full bg-white border-none rounded-xl p-3 text-xs min-h-[100px]"
                                    value={step.teacherActivity}
                                    onChange={e => {
                                      const newSteps = [...sheet.steps];
                                      newSteps[idx].teacherActivity = e.target.value;
                                      setSheet({...sheet, steps: newSteps});
                                    }}
                                  />
                               </div>
                               <div>
                                  <label className="text-[9px] font-black text-slate-400 uppercase">Activité de l'élève</label>
                                  <textarea 
                                    className="w-full bg-white border-none rounded-xl p-3 text-xs min-h-[100px]"
                                    value={step.studentActivity}
                                    onChange={e => {
                                      const newSteps = [...sheet.steps];
                                      newSteps[idx].studentActivity = e.target.value;
                                      setSheet({...sheet, steps: newSteps});
                                    }}
                                  />
                               </div>
                            </div>
                          </div>
                        ))}
                      </section>
                  </div>
                ) : (
                  <div ref={previewRef}>
                    <SheetPreview sheet={sheet} />
                  </div>
                )}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

