import { GoogleGenAI, Type } from "@google/genai";
import { GenerationRequest, SheetType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generatePedagogicalSheet = async (request: GenerationRequest & { type?: SheetType }) => {
  const { activity, gradeLevel, topic, language, type = SheetType.LESSON } = request;

  const systemInstruction = `Tu es l'Expert Ultime de l'Éducation Nationale Sénégalaise, détenteur de tous les Guides Pédagogiques du Curriculum de l'Éducation de Base (CEB) pour les Étapes 1 (CI-CP), 2 (CE1-CE2) et 3 (CM1-CM2).

  TON OBJECTIF : Générer des fiches d'une précision académique irréprochable selon l'Approche Par les Compétences (APC).

  CONTRAINTE CRITIQUE : La fiche doit être CONCISE pour tenir sur une seule page A4 une fois imprimée. 
  - Sois percutant dans les descriptions. 
  - Limite le nombre d'étapes de déroulement à 4 ou 5 maximum (les plus essentielles).
  - Évite les longs paragraphes, privilégie les tirets.

  CHAMP D'ACTION (DOMAINE ET DISCIPLINES) :
  - LANGUE ET COMMUNICATION : Français (Lecture, Écrit, Com. Orale), Arabe (Al-Lugha), Anglais (Step 3).
  - MATHÉMATIQUES : Activités Numériques, Géométrie, Mesure, Résolution de Problèmes.
  - ÉSVS : Découverte du monde, Histoire, Géographie, Initiation scientifique.
  - EDD : Vivre dans son milieu, Vivre ensemble.
  - ARTS ET SPORT : Éducation Artistique, EPSS.

  STRUCTURE TYPE APC :
  1. RÉVISION / MISE EN TRAIN : Rappel bref.
  2. MISE EN SITUATION : Problème concret contextualisé au Sénégal.
  3. ANALYSE / MANIPULATION : Action centrale élève/maître.
  4. SYNTHÈSE : L'essentiel à retenir.
  5. ÉVALUATION : Un item rapide.

  CONSIGNES DE RÉDACTION :
  - Utilise des prénoms sénégalais (Fatou, Moussa, Ami...).
  - Si la langue est l'Arabe, rédige les activités en Arabe mais garde la structure JSON en Français.
  - "Compétence de Base" et "Palier" doivent être exacts selon les guides officiels.`;

  const prompt = `Génère une fiche de type "${type}" pour la classe de "${gradeLevel}".
  Détails :
  - Activité/Discipline : "${activity}"
  - Titre de la leçon : "${topic}"
  - Langue : "${language}"

  Rends le contenu très synthétique mais complet pédagogiquement pour tenir sur une seule page A4.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          domain: { type: Type.STRING },
          subDomain: { type: Type.STRING },
          competence: { type: Type.STRING },
          level: { type: Type.STRING },
          oa: { type: Type.STRING },
          contentSummary: { type: Type.STRING },
          specificObjective: { type: Type.STRING },
          duration: { type: Type.STRING },
          reference: { type: Type.STRING },
          material: {
            type: Type.OBJECT,
            properties: {
              collective: { type: Type.STRING },
              individual: { type: Type.STRING }
            }
          },
          steps: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING, description: "Nom de l'étape (ex: Révision, Analyse...)" },
                objective: { type: Type.STRING, description: "Objectif intermédiaire" },
                teacherActivity: { type: Type.STRING, description: "Ce que fait le maître" },
                studentActivity: { type: Type.STRING, description: "Ce que font les élèves" }
              },
              required: ["name", "objective", "teacherActivity", "studentActivity"]
            }
          }
        },
        required: ["title", "domain", "subDomain", "competence", "level", "oa", "contentSummary", "specificObjective", "duration", "steps"]
      },
    },
  });

  try {
    const text = response.text;
    if (!text) throw new Error("Réponse vide.");
    const data = JSON.parse(text);
    return {
      ...data,
      id: Math.random().toString(36).substr(2, 9),
      createdAt: Date.now(),
      type: type,
      subject: activity,
      gradeLevel
    };
  } catch (error) {
    console.error("Gemini Error:", error);
    throw new Error("Impossible de générer la fiche pédagogique.");
  }
};

