  Titre de la leçon : "${topic}"
  Langue : "${language}"

  Assure-toi que la formulation de l'Objectif Spécifique (OS) commence par : "À l'issue de la séance, l'élève devra être capable de..."`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          domain: { type: Type.STRING },
          subDomain: { type: Type.STRING },
          discipline: { type: Type.STRING },
          activity: { type: Type.STRING },
          competence: { type: Type.STRING },
          level: { type: Type.STRING },
          oa: { type: Type.STRING },
          contentSummary: { type: Type.STRING },
          specificObjective: { type: Type.STRING },
          duration: { type: Type.STRING },
          reference: { type: Type.STRING },
          material: {
            type: Type.OBJECT,
            properties: {
              collective: { type: Type.STRING },
              individual: { type: Type.STRING }
            }
          },
          steps: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING, description: "Nom de l'étape (Mise en train, Situation-Problème, etc.)" },
                objective: { type: Type.STRING, description: "Objectif de l'étape" },
                teacherActivity: { type: Type.STRING, description: "Actions du Maître" },
                studentActivity: { type: Type.STRING, description: "Actions des Éleves" }
              },
              required: ["name", "objective", "teacherActivity", "studentActivity"]
            }
          }
        },
        required: ["title", "domain", "subDomain", "competence", "level", "oa", "contentSummary", "specificObjective", "duration", "steps"]
      },
    },
  });

  try {
    const text = response.text;
    if (!text) throw new Error("Réponse vide.");
    const data = JSON.parse(text);
    return {
      ...data,
      id: Math.random().toString(36).substr(2, 9),
      createdAt: Date.now(),
      type: type,
      subject: data.activity || activity,
      gradeLevel
    };
  } catch (error) {
    console.error("Gemini Error:", error);
    throw new Error("Erreur lors de la génération. Vérifiez vos paramètres.");
  }
};

export enum SheetType {
