import { GoogleGenAI, Type } from "@google/genai";
import { GenerationRequest, SheetType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Nettoie la chaîne de caractères pour extraire uniquement le contenu JSON
 * Utile si le modèle entoure la réponse de blocs de code markdown.
 */
const cleanJsonString = (str: string): string => {
  const jsonMatch = str.match(/\{[\s\S]*\}/);
  return jsonMatch ? jsonMatch[0] : str;
};

export const generatePedagogicalSheet = async (request: GenerationRequest & { type?: SheetType }) => {
  const { activity, gradeLevel, topic, language, type = SheetType.LESSON } = request;

  const systemInstruction = `Tu es un Expert Consultant pour le Ministère de l'Éducation Nationale du Sénégal (MEN). 
  Ta mission est de concevoir une fiche de préparation rigoureusement conforme au Curriculum de l'Éducation de Base (CEB) et à l'Approche Par les Compétences (APC).

  TERMINOLOGIE OBLIGATOIRE À RESPECTER :
  - DOMAINE : (ex: Langue et Communication, Mathématiques, ESVS, EDD, Arts et Sport).
  - SOUS-DOMAINE : (ex: Communication Orale, Activités Numériques, Découverte du Monde).
  - DISCIPLINE : La matière générale (ex: Français, Mathématiques, Histoire).
  - ACTIVITÉ : La compétence spécifique (ex: Grammaire, Géométrie, Lecture, Initiation Scientifique).
  - CB (Compétence de Base) : La compétence terminale visée par le palier.
  - PALIER : L'étape de développement de la compétence.
  - OA (Objectif d'Apprentissage) : Ce que l'élève doit apprendre.
  - OS (Objectif Spécifique) : L'objectif opérationnel de la séance (À l'issue de la séance, l'élève doit être capable de...).

  STRUCTURE DES ÉTAPES (DÉROULEMENT) :
  1. MISE EN TRAIN / RÉVISION : Rappel des acquis liés à la leçon.
  2. MISE EN SITUATION : Présentation d'une SITUATION-PROBLÈME concrète, contextualisée au Sénégal (prénoms, lieux, faits sociaux).
  3. CONSTRUCTION DES CONNAISSANCES (Analyse/Manipulation) : Phase active de recherche et d'échanges.
  4. SYNTHÈSE : Co-construction de la règle ou de la trace écrite (concise).
  5. ÉVALUATION : Exercice ou item pour vérifier l'atteinte de l'OS.

  RETOURNE EXCLUSIVEMENT DU JSON.`;

  const prompt = `Génère une fiche de type "${type}" pour la classe de "${gradeLevel}".
  Discipline/Activité : "${activity}"
  Titre de la leçon : "${topic}"
  Langue : "${language}"

  Assure-toi que la formulation de l'Objectif Spécifique (OS) commence par : "À l'issue de la séance, l'élève devra être capable de..."`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            domain: { type: Type.STRING },
            subDomain: { type: Type.STRING },
            discipline: { type: Type.STRING },
            activity: { type: Type.STRING },
            competence: { type: Type.STRING },
            level: { type: Type.STRING },
            oa: { type: Type.STRING },
            contentSummary: { type: Type.STRING },
            specificObjective: { type: Type.STRING },
            duration: { type: Type.STRING },
            reference: { type: Type.STRING },
            material: {
              type: Type.OBJECT,
              properties: {
                collective: { type: Type.STRING },
                individual: { type: Type.STRING }
              }
            },
            steps: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  objective: { type: Type.STRING },
                  teacherActivity: { type: Type.STRING },
                  studentActivity: { type: Type.STRING }
                },
                required: ["name", "objective", "teacherActivity", "studentActivity"]
              }
            }
          },
          required: ["title", "domain", "subDomain", "competence", "level", "oa", "contentSummary", "specificObjective", "duration", "steps"]
        },
      },
    });

    const text = response.text;
    if (!text) throw new Error("Réponse vide de l'IA.");

    const data = JSON.parse(cleanJsonString(text));

    return {
      ...data,
      id: Math.random().toString(36).substr(2, 9),
      createdAt: Date.now(),
      type: type,
      subject: data.activity || activity,
      gradeLevel
    };
  } catch (error) {
    console.error("Gemini Error:", error);
    throw new Error("Erreur lors de la génération. Veuillez réessayer ou simplifier votre demande.");
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { PedagogicalSheet, SheetType, GenerationRequest } from '../types';
import { generatePedagogicalSheet } from '../services/geminiService';
import SheetPreview from './SheetPreview';

interface SheetEditorProps {
  sheets?: PedagogicalSheet[];
  onSave: (sheet: PedagogicalSheet) => void;
}

const SheetEditor: React.FC<SheetEditorProps> = ({ sheets = [], onSave }) => {
  const { id } = useParams();
  const navigate = useNavigate();
  const previewRef = useRef<HTMLDivElement>(null);
  const [loading, setLoading] = useState(false);
  const [pdfLoading, setPdfLoading] = useState(false);
  const [saveSuccess, setSaveSuccess] = useState(false);
  const [viewMode, setViewMode] = useState<'edit' | 'preview'>('edit');

  const [formData, setFormData] = useState<GenerationRequest & { type: SheetType }>({
    activity: '',
    gradeLevel: 'CM2',
    topic: '',
    language: 'Français',
    type: SheetType.LESSON
  });

  const [sheet, setSheet] = useState<PedagogicalSheet | null>(null);

  useEffect(() => {
    if (id) {
      const existing = sheets.find(s => s.id === id);
      if (existing) {
        setSheet(existing);
        setFormData({
          activity: existing.subject,
          gradeLevel: existing.gradeLevel,
          topic: existing.title,
          language: 'Français',
          type: existing.type
        });
      }
    }
  }, [id, sheets]);

  const handleGenerate = async () => {
    if (!formData.activity || !formData.topic) {
      alert("Veuillez renseigner la discipline et le titre de la leçon.");
      return;
    }

    setLoading(true);
    try {
      const generated = await generatePedagogicalSheet(formData);
      setSheet({ ...generated, type: formData.type });
      setViewMode('preview');
    } catch (error: any) {
      console.error(error);
      alert(error.message || "Erreur lors de la génération.");
    } finally {
      setLoading(false);
    }
  };

  const handleSave = () => {
    if (sheet) {
      onSave(sheet);
      setSaveSuccess(true);
      setTimeout(() => {
        setSaveSuccess(false);
        navigate('/');
      }, 1500);
    }
  };

  const handlePrint = () => {
    if (viewMode === 'edit') {
        setViewMode('preview');
        setTimeout(() => window.print(), 200);
    } else {
        window.print();
    }
  };

  const exportToPDF = async () => {
    if (!sheet) return;

    if (viewMode === 'edit') {
      setViewMode('preview');
      setTimeout(() => triggerPdf(), 300);
    } else {
      triggerPdf();
    }
  };

  const triggerPdf = async () => {
    if (!previewRef.current || !sheet) {
      alert("Aperçu non disponible.");
      return;
    }

    setPdfLoading(true);
    try {
      const element = previewRef.current;
      const opt = {
        margin: [8, 5, 8, 5],
        filename: `Fiche_${sheet.title.replace(/\s+/g, '_')}.pdf`,
        image: { type: 'jpeg', quality: 0.98 },
        html2canvas: { scale: 2, useCORS: true, logging: false },
        jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
      };

      // Utilisation du script chargé globalement via index.html
      const h2p = (window as any).html2pdf;

      if (typeof h2p === 'function') {
        await h2p().set(opt).from(element).save();
      } else {
        throw new Error("Bibliothèque d'exportation non chargée.");
      }
    } catch (err) {
      console.error("PDF Export Error:", err);
      alert("L'exportation PDF a échoué. Utilisez 'Imprimer' > 'Enregistrer en PDF'.");
    } finally {
      setPdfLoading(false);
    }
  };

  const exportToWord = () => {
    if (!previewRef.current || !sheet) return;
    const content = previewRef.current.innerHTML;
    const header = `<html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'><head><meta charset='utf-8'><title>${sheet.title}</title><style>body { font-family: 'Arial'; font-size: 10pt; } table { border-collapse: collapse; width: 100%; border: 1px solid black; } th, td { border: 1px solid black; padding: 4px; }</style></head><body>${content}</body></html>`;
    const blob = new Blob(['\ufeff', header], { type: 'application/msword' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Fiche_${sheet.title}.doc`;
    link.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      {saveSuccess && (
        <div className="fixed top-20 right-4 z-[100] bg-emerald-600 text-white px-6 py-4 rounded-2xl shadow-2xl flex items-center space-x-3 animate-bounce">
          <i className="fas fa-check-circle text-xl"></i>
          <span className="font-bold">Fiche enregistrée !</span>
        </div>
      )}

      {pdfLoading && (
        <div className="fixed inset-0 z-[200] bg-slate-900/40 backdrop-blur-sm flex items-center justify-center">
          <div className="bg-white p-8 rounded-[2.5rem] shadow-2xl flex flex-col items-center space-y-4">
            <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-black text-slate-800 uppercase tracking-widest text-sm text-center">
              Préparation de votre PDF...
