                     { id: SheetType.EXERCISE, label: 'TD/Exos', icon: 'pencil-alt' },
                     { id: SheetType.EVALUATION, label: 'Évaluation', icon: 'star' }
                   ].map(type => (
                     <button 
                      key={type.id}
                      onClick={() => setFormData({...formData, type: type.id as SheetType})}
                      className={`flex flex-col items-center py-3 rounded-xl border transition-all ${formData.type === type.id ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-500 hover:border-indigo-200'}`}
