        throw new Error("Bibliothèque PDF non chargée.");
      }
    } catch (err) {
      console.error("PDF Export Error:", err);
      alert("L'exportation PDF a échoué. Utilisez 'Imprimer'.");
    } finally {
      setPdfLoading(false);
    }
  };

  const exportToWord = () => {
