import { GoogleGenAI, Type } from "@google/genai";
import { GenerationRequest, SheetType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const cleanJsonString = (str: string): string => {
  const jsonMatch = str.match(/\{[\s\S]*\}/);
  return jsonMatch ? jsonMatch[0] : str;
};

export const generatePedagogicalSheet = async (request: GenerationRequest & { type?: SheetType }) => {
  const { activity, gradeLevel, topic, language, type = SheetType.LESSON } = request;

  const systemInstruction = `Tu es un Expert Consultant pour le Ministère de l'Éducation Nationale du Sénégal (MEN), spécialiste du Curriculum de l'Éducation de Base (CEB).

  CONTEXTES COUVERTS : 
  1. ÉCOLES PUBLIQUES : Tous domaines (Langue, Math, ESVS, EDD, Arts, Sports, Anglais).
  2. ÉCOLES FRANCO-ARABES : Tawhid, Fiqh, Sirah, Hadith, Coran, Langue Arabe.

  CONTRAINTE ABSOLUE : La fiche doit être extrêmement CONCISE pour tenir sur UNE SEULE PAGE A4 (maximum 5 étapes). 
  Rédige des descriptions d'activités percutantes et courtes.

  TERMINOLOGIE :
  - Utilise les termes officiels du CEB : DOMAINE, SOUS-DOMAINE, CB, PALIER, OA, OS.
  - OS (Objectif Spécifique) : Doit commencer par "À l'issue de la séance, l'élève devra être capable de..." (traduit si nécessaire).

  STRUCTURE APC :
  - Étape 1 : Mise en train / Révision.
  - Étape 2 : Mise en situation (Situation-problème courte).
  - Étape 3 : Construction des connaissances.
  - Étape 4 : Synthèse (Trace écrite très brève).
  - Étape 5 : Évaluation.

  RETOURNE EXCLUSIVEMENT DU JSON SANS TEXTE AVANT OU APRÈS.`;

  const prompt = `Génère une fiche de type "${type}" pour la classe de "${gradeLevel}".
  Discipline/Activité : "${activity}"
  Titre de la leçon : "${topic}"
  Langue : "${language}" (Rédige l'intégralité du contenu en ${language}).`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            domain: { type: Type.STRING },
            subDomain: { type: Type.STRING },
            discipline: { type: Type.STRING },
            activity: { type: Type.STRING },
            competence: { type: Type.STRING },
            level: { type: Type.STRING },
            oa: { type: Type.STRING },
            contentSummary: { type: Type.STRING },
            specificObjective: { type: Type.STRING },
            duration: { type: Type.STRING },
            reference: { type: Type.STRING },
            material: {
              type: Type.OBJECT,
              properties: {
                collective: { type: Type.STRING },
                individual: { type: Type.STRING }
              }
            },
            steps: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  objective: { type: Type.STRING },
                  teacherActivity: { type: Type.STRING },
                  studentActivity: { type: Type.STRING }
                },
                required: ["name", "objective", "teacherActivity", "studentActivity"]
              }
            }
          },
          required: ["title", "domain", "subDomain", "competence", "level", "oa", "contentSummary", "specificObjective", "duration", "steps"]
        },
      },
    });

    const text = response.text;
    if (!text) throw new Error("Erreur : Réponse IA vide.");

    const data = JSON.parse(cleanJsonString(text));

    return {
      ...data,
      id: Math.random().toString(36).substr(2, 9),
      createdAt: Date.now(),
      type: type,
      subject: data.activity || activity,
      gradeLevel
    };
  } catch (error) {
    console.error("Gemini Error:", error);
    throw new Error("Impossible de générer la fiche. Veuillez réessayer avec un sujet plus simple.");
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { PedagogicalSheet, SheetType, GenerationRequest } from '../types';
import { generatePedagogicalSheet } from '../services/geminiService';
import SheetPreview from './SheetPreview';

interface SheetEditorProps {
  sheets?: PedagogicalSheet[];
  onSave: (sheet: PedagogicalSheet) => void;
}

const SheetEditor: React.FC<SheetEditorProps> = ({ sheets = [], onSave }) => {
  const { id } = useParams();
  const navigate = useNavigate();
  const previewRef = useRef<HTMLDivElement>(null);
  const [loading, setLoading] = useState(false);
  const [pdfLoading, setPdfLoading] = useState(false);
  const [saveSuccess, setSaveSuccess] = useState(false);
  const [viewMode, setViewMode] = useState<'edit' | 'preview'>('edit');

  const [formData, setFormData] = useState<GenerationRequest & { type: SheetType }>({
    activity: '',
    gradeLevel: 'CM2',
    topic: '',
    language: 'Français',
    type: SheetType.LESSON
  });

  const [sheet, setSheet] = useState<PedagogicalSheet | null>(null);

  useEffect(() => {
    if (id) {
      const existing = sheets.find(s => s.id === id);
      if (existing) {
        setSheet(existing);
        setFormData({
          activity: existing.subject,
          gradeLevel: existing.gradeLevel,
          topic: existing.title,
          language: 'Français',
          type: existing.type
        });
      }
    }
  }, [id, sheets]);

  const handleGenerate = async () => {
    if (!formData.activity || !formData.topic) {
      alert("Veuillez renseigner la discipline et le titre de la leçon.");
      return;
    }

    setLoading(true);
    try {
      const generated = await generatePedagogicalSheet(formData);
      setSheet({ ...generated, type: formData.type });
      setViewMode('preview');
    } catch (error: any) {
      console.error(error);
      alert(error.message || "Erreur de génération.");
    } finally {
      setLoading(false);
    }
  };

  const handleSave = () => {
    if (sheet) {
      onSave(sheet);
      setSaveSuccess(true);
      setTimeout(() => {
        setSaveSuccess(false);
        navigate('/');
      }, 1500);
    }
  };

  const handlePrint = () => {
    if (viewMode === 'edit') {
        setViewMode('preview');
        setTimeout(() => window.print(), 300);
    } else {
        window.print();
    }
  };

  const exportToPDF = async () => {
    if (!sheet) return;

    // Forcer le mode aperçu pour capturer le rendu final
    if (viewMode === 'edit') {
      setViewMode('preview');
      setTimeout(() => triggerPdf(), 500);
    } else {
      triggerPdf();
    }
  };

  const triggerPdf = async () => {
    if (!previewRef.current || !sheet) {
      alert("Erreur : Contenu non prêt.");
      return;
    }

    setPdfLoading(true);
    try {
      const element = previewRef.current;
      const opt = {
        margin: [5, 5, 5, 5],
        filename: `Fiche_APC_${sheet.title.replace(/\s+/g, '_')}.pdf`,
        image: { type: 'jpeg', quality: 0.98 },
        html2canvas: { 
          scale: 2, 
          useCORS: true, 
          logging: false 
        },
        jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
        pagebreak: { mode: ['avoid-all', 'css', 'legacy'] }
      };

      // Utilisation robuste de l'API globale
      const html2pdfLib = (window as any).html2pdf;

      if (typeof html2pdfLib === 'function') {
        await html2pdfLib().set(opt).from(element).save();
      } else {
        throw new Error("html2pdf is not a function");
      }
    } catch (err) {
      console.error("PDF Error:", err);
      alert("L'exportation directe a échoué. Utilisez 'Imprimer' et choisissez 'Enregistrer au format PDF'.");
    } finally {
      setPdfLoading(false);
    }
  };

  const exportToWord = () => {
    if (!previewRef.current || !sheet) return;
    const content = previewRef.current.innerHTML;
    const header = `<html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'><head><meta charset='utf-8'><title>${sheet.title}</title><style>body { font-family: 'Arial'; font-size: 10pt; } table { border-collapse: collapse; width: 100%; border: 1px solid black; } th, td { border: 1px solid black; padding: 4px; }</style></head><body>${content}</body></html>`;
    const blob = new Blob(['\ufeff', header], { type: 'application/msword' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Fiche_${sheet.title}.doc`;
    link.click();
    URL.revokeObjectURL(url);
