import { GoogleGenAI, Type } from "@google/genai";
import { GenerationRequest, SheetType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const cleanJsonString = (str: string): string => {
  const jsonMatch = str.match(/\{[\s\S]*\}/);
  return jsonMatch ? jsonMatch[0] : str;
};

export const generatePedagogicalSheet = async (request: GenerationRequest & { type?: SheetType }) => {
  const { activity, gradeLevel, topic, language, type = SheetType.LESSON } = request;

  const systemInstruction = `Tu es l'Expert Ultime en Ingénierie Pédagogique pour le Ministère de l'Éducation Nationale du Sénégal. Ta mission est de produire une fiche APC (Approche Par les Compétences) d'une qualité professionnelle exceptionnelle.

  DIRECTIVES DE GÉNÉRATION (DÉCLINAISON COMPLÈTE) :
  1. DÉCLINAISON CURRICULAIRE : Identifie avec précision le DOMAINE (ex: Langue et Communication), le SOUS-DOMAINE (ex: Écriture), la DISCIPLINE et l'ACTIVITÉ selon le guide CEB officiel.
  2. COMPÉTENCE & PALIER : Formule une CB (Compétence de Base) et un PALIER cohérents avec le niveau ${gradeLevel}.
  3. OBJECTIF SPÉCIFIQUE (OS) : Doit être mesurable, observable et commencer par "À l'issue de la séance, l'élève devra être capable de...". Utilise des verbes d'action précis (identifier, classer, résoudre, produire).
  4. VOCABULAIRE ENRICHI : Utilise un langage pédagogique soutenu mais clair. Évite les répétitions. Enrichis les consignes du maître.

  ADAPTATION PAR NIVEAU (${gradeLevel}) :
  - CI/CP : Phrases très courtes, vocabulaire concret, résumé (synthèse) ultra-simplifié (souvent une seule phrase ou une règle visuelle).
  - CE1/CE2 : Introduction de définitions simples, vocabulaire plus technique, résumé structuré en 2-3 points.
  - CM1/CM2 : Raisonnement abstrait, vocabulaire spécialisé, synthèse complète avec exemples et exceptions si nécessaire.

  STRUCTURE DU DÉROULEMENT (5 ÉTAPES MAX) :
  - Mise en train : Rappel pré-requis.
  - Mise en situation : Situation-problème contextualisée (prénoms/lieux sénégalais).
  - Construction : Manipulation, recherche, échanges.
  - Synthèse (Trace écrite) : Résumé adapté au niveau ${gradeLevel}.
  - Évaluation : Vérification immédiate de l'OS.

  RETOURNE EXCLUSIVEMENT DU JSON.`;

  const prompt = `Génère une fiche de type "${type}" en "${language}" pour la classe de "${gradeLevel}".
  Discipline/Activité : "${activity}"
  Titre : "${topic}"

  Assure-toi que le résumé (trace écrite) est parfaitement calibré pour des élèves de ${gradeLevel}.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            domain: { type: Type.STRING, description: "Domaine CEB (ex: Langue et Communication)" },
            subDomain: { type: Type.STRING, description: "Sous-domaine CEB" },
            discipline: { type: Type.STRING },
            activity: { type: Type.STRING },
            competence: { type: Type.STRING, description: "Compétence de base (CB) complète" },
            level: { type: Type.STRING, description: "Le palier visé" },
            oa: { type: Type.STRING, description: "Objectif d'Apprentissage (OA)" },
            contentSummary: { type: Type.STRING, description: "Le contenu notionnel" },
            specificObjective: { type: Type.STRING },
            duration: { type: Type.STRING, description: "Durée (ex: 30 min, 45 min)" },
            reference: { type: Type.STRING },
            material: {
              type: Type.OBJECT,
              properties: {
                collective: { type: Type.STRING },
                individual: { type: Type.STRING }
              }
            },
            steps: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  objective: { type: Type.STRING },
                  teacherActivity: { type: Type.STRING },
                  studentActivity: { type: Type.STRING }
                },
                required: ["name", "objective", "teacherActivity", "studentActivity"]
              }
            }
          },
          required: ["title", "domain", "subDomain", "competence", "level", "oa", "specificObjective", "duration", "steps"]
        },
      },
    });

    const text = response.text;
    if (!text) throw new Error("Réponse IA vide.");

    const data = JSON.parse(cleanJsonString(text));

    return {
      ...data,
      id: Math.random().toString(36).substr(2, 9),
      createdAt: Date.now(),
      type: type,
      subject: data.activity || activity,
      gradeLevel
    };
  } catch (error) {
    console.error("Gemini Error:", error);
    throw new Error("Échec de la conception. L'IA n'a pas pu structurer la fiche selon les normes CEB. Réessayez.");
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { PedagogicalSheet, SheetType, GenerationRequest } from '../types';
import { generatePedagogicalSheet } from '../services/geminiService';
import SheetPreview from './SheetPreview';

interface SheetEditorProps {
  sheets?: PedagogicalSheet[];
  onSave: (sheet: PedagogicalSheet) => void;
}

const SheetEditor: React.FC<SheetEditorProps> = ({ sheets = [], onSave }) => {
  const { id } = useParams();
  const navigate = useNavigate();
  const previewRef = useRef<HTMLDivElement>(null);
  const [loading, setLoading] = useState(false);
  const [pdfLoading, setPdfLoading] = useState(false);
  const [saveSuccess, setSaveSuccess] = useState(false);
  const [viewMode, setViewMode] = useState<'edit' | 'preview'>('edit');

  const [formData, setFormData] = useState<GenerationRequest & { type: SheetType }>({
    activity: '',
    gradeLevel: 'CM2',
    topic: '',
    language: 'Français',
    type: SheetType.LESSON
  });

  const [sheet, setSheet] = useState<PedagogicalSheet | null>(null);

  useEffect(() => {
    if (id) {
      const existing = sheets.find(s => s.id === id);
      if (existing) {
        setSheet(existing);
        setFormData({
          activity: existing.subject,
          gradeLevel: existing.gradeLevel,
          topic: existing.title,
          language: 'Français',
          type: existing.type
        });
      }
    }
  }, [id, sheets]);

  const handleGenerate = async () => {
    if (!formData.activity || !formData.topic) {
      alert("Veuillez renseigner l'activité et le titre de la leçon.");
      return;
    }

    setLoading(true);
    try {
      const generated = await generatePedagogicalSheet(formData);
      setSheet({ ...generated, type: formData.type });
      setViewMode('preview');
    } catch (error: any) {
      console.error(error);
      alert(error.message || "Erreur lors de l'élaboration de la fiche.");
    } finally {
      setLoading(false);
    }
  };

  const handleSave = () => {
    if (sheet) {
      onSave(sheet);
      setSaveSuccess(true);
      setTimeout(() => {
        setSaveSuccess(false);
        navigate('/');
      }, 1500);
    }
  };

  const handlePrint = () => {
    if (viewMode === 'edit') {
        setViewMode('preview');
        setTimeout(() => window.print(), 300);
    } else {
        window.print();
    }
  };

  const exportToPDF = async () => {
    if (!sheet) return;

    if (viewMode === 'edit') {
      setViewMode('preview');
      setTimeout(() => triggerPdf(), 600);
    } else {
      triggerPdf();
    }
  };

  const triggerPdf = async () => {
    if (!previewRef.current || !sheet) {
      alert("Préparation du contenu impossible.");
      return;
    }

    setPdfLoading(true);
    try {
      const element = previewRef.current;
      const opt = {
        margin: [5, 5, 5, 5],
        filename: `Fiche_APC_${sheet.gradeLevel}_${sheet.title.replace(/\s+/g, '_')}.pdf`,
        image: { type: 'jpeg', quality: 0.98 },
        html2canvas: { scale: 2, useCORS: true, logging: false },
        jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
        pagebreak: { mode: ['avoid-all', 'css', 'legacy'] }
      };

      const html2pdfLib = (window as any).html2pdf;
      if (typeof html2pdfLib === 'function') {
        await html2pdfLib().set(opt).from(element).save();
      } else {
        throw new Error("Bibliothèque PDF introuvable.");
      }
    } catch (err) {
      console.error("PDF Export Error:", err);
      alert("L'exportation directe a échoué. Utilisez le menu 'Imprimer' de votre navigateur.");
    } finally {
      setPdfLoading(false);
    }
  };

  const exportToWord = () => {
    if (!previewRef.current || !sheet) return;
    const content = previewRef.current.innerHTML;
    const header = `<html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'><head><meta charset='utf-8'><title>${sheet.title}</title><style>body { font-family: 'Arial'; font-size: 10pt; } table { border-collapse: collapse; width: 100%; border: 1px solid black; } th, td { border: 1px solid black; padding: 4px; }</style></head><body>${content}</body></html>`;
    const blob = new Blob(['\ufeff', header], { type: 'application/msword' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Fiche_${sheet.title}.doc`;
    link.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      {saveSuccess && (
        <div className="fixed top-20 right-4 z-[100] bg-emerald-600 text-white px-6 py-4 rounded-2xl shadow-2xl flex items-center space-x-3 animate-bounce">
          <i className="fas fa-check-circle text-xl"></i>
          <span className="font-bold">Déclinaison enregistrée !</span>
        </div>
      )}

      {pdfLoading && (
        <div className="fixed inset-0 z-[200] bg-slate-900/60 backdrop-blur-sm flex items-center justify-center">
          <div className="bg-white p-10 rounded-[2.5rem] shadow-2xl flex flex-col items-center space-y-4">
            <div className="w-14 h-14 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-black text-slate-800 uppercase tracking-widest text-xs text-center leading-relaxed">
              Formatage A4 Monopage...<br/>
              <span className="text-[10px] text-slate-400 font-medium">Exportation haute qualité en cours</span>
            </p>
          </div>
        </div>
      )}

      <div className="flex flex-col lg:flex-row gap-8">
        <div className="lg:w-1/3 no-print">
          <div className="bg-white border border-slate-200 rounded-3xl p-6 shadow-sm sticky top-24">
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-xl font-black text-slate-900 flex items-center">
                <i className="fas fa-microchip mr-3 text-indigo-600"></i>
                Intelligence APC
              </h2>
              <div className="flex flex-col items-end">
                <span className="bg-indigo-50 text-indigo-600 px-3 py-1 rounded-lg text-[10px] font-black border border-indigo-100 uppercase">
                  Normes CEB
                </span>
              </div>
            </div>

            <div className="space-y-5">
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase mb-2 tracking-widest">Format du document</label>
                <div className="grid grid-cols-3 gap-2">
                   {[
                     { id: SheetType.LESSON, label: 'Leçon', icon: 'chalkboard' },
                     { id: SheetType.EXERCISE, label: 'Td/Exos', icon: 'pencil-alt' },
                     { id: SheetType.EVALUATION, label: 'Éval.', icon: 'star' }
                   ].map(type => (
                     <button 
                      key={type.id}
