                <button onClick={handleSave} className="w-full py-3 bg-slate-900 text-white rounded-2xl font-black hover:bg-slate-800 transition-all flex items-center justify-center uppercase text-xs tracking-wider">
                  <i className="fas fa-save mr-2"></i> Enregistrer
                </button>
                <div className="grid grid-cols-3 gap-2">
