import { GoogleGenAI, Type } from "@google/genai";
import { GenerationRequest, SheetType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const cleanJsonString = (str: string): string => {
  const jsonMatch = str.match(/\{[\s\S]*\}/);
  return jsonMatch ? jsonMatch[0] : str;
};

export const generatePedagogicalSheet = async (request: GenerationRequest & { type?: SheetType }) => {
  const { activity, gradeLevel, topic, language, type = SheetType.LESSON } = request;

  const systemInstruction = `Tu es l'Expert de référence du Ministère de l'Éducation Nationale du Sénégal. Tu maîtrises parfaitement le Guide Pédagogique du CEB pour TOUTES les classes (CI, CP, CE1, CE2, CM1, CM2) et TOUTES les disciplines.

  CONTEXTE DE RÉFÉRENCE (CEB SÉNÉGAL) :
  1. LANGUE ET COMMUNICATION (LC) : Communication Orale, Lecture, Écriture, Production d'écrits, Grammaire, Conjugaison, Orthographe, Vocabulaire.
  2. MATHÉMATIQUES : Activités Numériques, Géométrie, Mesure, Résolution de problèmes.
  3. ESVS : Histoire, Géographie, Initiation Scientifique et Technologique.
  4. EDD (Éducation au Développement Durable) : Vivre Ensemble, Vivre dans son Milieu.
  5. ARTS & SPORTS : Arts Plastiques, Éducation Musicale, EPS.
  6. FRANCO-ARABE : Tawhid, Fiqh, Sirah, Hadith, Coran (Hifz/Tajwid), Langue Arabe (Nahw, Sarf, Imla, Incha).
  7. ANGLAIS : Initiation à l'anglais oral et écrit.

  TA MISSION :
  - Décliner avec précision le DOMAINE, SOUS-DOMAINE, CB, PALIER et OA conformément au guide pour le niveau ${gradeLevel}.
  - Enrichir le vocabulaire pédagogique : utilise des termes comme "matérialisation", "confrontation", "validation", "institutionnalisation".
  - Résumé adapté : Pour un ${gradeLevel}, le résumé doit être calibré (CI/CP = 1 phrase simple ; CM = Synthèse structurée).

  STRUCTURE DE LA FICHE (MODÈLE APC OFFICIEL) :
  - Mise en train : Rappel de pré-requis ou jeu éducatif.
  - Mise en situation : Situation-problème contextualisée au Sénégal (lieux, prénoms locaux).
  - Construction des connaissances : Démarche active (Observation -> Hypothèses -> Vérification -> Synthèse).
  - Évaluation : Exercice d'application immédiate de l'OS.

  RETOURNE EXCLUSIVEMENT DU JSON.`;

  const prompt = `Génère une fiche de préparation complète pour :
  Niveau : "${gradeLevel}"
  Discipline/Activité : "${activity}"
  Titre de la leçon : "${topic}"
  Type : "${type}"
  Langue de rédaction : "${language}"

  Assure-toi que tout le contenu (titres, activités, résumé) est rédigé en "${language}".`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            domain: { type: Type.STRING },
            subDomain: { type: Type.STRING },
            discipline: { type: Type.STRING },
            activity: { type: Type.STRING },
            competence: { type: Type.STRING },
            level: { type: Type.STRING },
            oa: { type: Type.STRING },
            contentSummary: { type: Type.STRING },
            specificObjective: { type: Type.STRING },
            duration: { type: Type.STRING },
            reference: { type: Type.STRING },
            material: {
              type: Type.OBJECT,
              properties: {
                collective: { type: Type.STRING },
                individual: { type: Type.STRING }
              }
            },
            steps: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  objective: { type: Type.STRING },
                  teacherActivity: { type: Type.STRING },
                  studentActivity: { type: Type.STRING }
                },
                required: ["name", "objective", "teacherActivity", "studentActivity"]
              }
            }
          },
          required: ["title", "domain", "subDomain", "competence", "level", "oa", "specificObjective", "duration", "steps"]
        },
      },
    });

    const text = response.text;
    if (!text) throw new Error("Réponse vide de l'IA.");

    const data = JSON.parse(cleanJsonString(text));

    return {
      ...data,
      id: Math.random().toString(36).substr(2, 9),
      createdAt: Date.now(),
      type: type,
      subject: data.activity || activity,
      gradeLevel
    };
  } catch (error) {
    console.error("Gemini Error:", error);
    throw new Error("Erreur lors de la génération. Veuillez vérifier la connexion ou les paramètres.");
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { PedagogicalSheet, SheetType, GenerationRequest } from '../types';
import { generatePedagogicalSheet } from '../services/geminiService';
import SheetPreview from './SheetPreview';

interface SheetEditorProps {
  sheets?: PedagogicalSheet[];
  onSave: (sheet: PedagogicalSheet) => void;
}

const SheetEditor: React.FC<SheetEditorProps> = ({ sheets = [], onSave }) => {
  const { id } = useParams();
  const navigate = useNavigate();
  const previewRef = useRef<HTMLDivElement>(null);
  const [loading, setLoading] = useState(false);
  const [pdfLoading, setPdfLoading] = useState(false);
  const [saveSuccess, setSaveSuccess] = useState(false);
  const [viewMode, setViewMode] = useState<'edit' | 'preview'>('edit');

  const [formData, setFormData] = useState<GenerationRequest & { type: SheetType }>({
    activity: '',
    gradeLevel: 'CM2',
    topic: '',
    language: 'Français',
    type: SheetType.LESSON
  });

  const [sheet, setSheet] = useState<PedagogicalSheet | null>(null);

  useEffect(() => {
    if (id) {
      const existing = sheets.find(s => s.id === id);
      if (existing) {
        setSheet(existing);
        setFormData({
          activity: existing.subject,
          gradeLevel: existing.gradeLevel,
          topic: existing.title,
          language: 'Français',
          type: existing.type
        });
      }
    }
  }, [id, sheets]);

  const handleGenerate = async () => {
    if (!formData.activity || !formData.topic) {
      alert("Précisez l'activité et le titre pour interroger le guide.");
      return;
    }

    setLoading(true);
    try {
      const generated = await generatePedagogicalSheet(formData);
      setSheet({ ...generated, type: formData.type });
      setViewMode('preview');
    } catch (error: any) {
      console.error(error);
      alert(error.message || "Erreur de connexion au guide pédagogique IA.");
    } finally {
      setLoading(false);
    }
  };

  const handleSave = () => {
    if (sheet) {
      onSave(sheet);
      setSaveSuccess(true);
      setTimeout(() => {
        setSaveSuccess(false);
        navigate('/');
      }, 1500);
    }
  };

  const handlePrint = () => {
    if (viewMode === 'edit') {
        setViewMode('preview');
        setTimeout(() => window.print(), 500);
    } else {
        window.print();
    }
  };

  const exportToPDF = async () => {
    if (!sheet) return;
    if (viewMode === 'edit') {
      setViewMode('preview');
      setTimeout(() => triggerPdf(), 800);
    } else {
      triggerPdf();
    }
  };

  const triggerPdf = async () => {
    if (!previewRef.current || !sheet) return;

    setPdfLoading(true);
    try {
      const element = previewRef.current;
      const opt = {
        margin: [0, 0, 0, 0],
        filename: `CEB_SENEGAL_${sheet.gradeLevel}_${sheet.title.replace(/\s+/g, '_')}.pdf`,
        image: { type: 'jpeg', quality: 1.0 },
        html2canvas: { scale: 2, useCORS: true, letterRendering: true },
        jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
      };

      const html2pdfLib = (window as any).html2pdf;
      if (typeof html2pdfLib === 'function') {
        await html2pdfLib().set(opt).from(element).save();
      } else {
        throw new Error("html2pdf non disponible.");
      }
    } catch (err) {
      console.error(err);
      alert("Échec de l'export. Utilisez l'impression PDF.");
    } finally {
      setPdfLoading(false);
    }
  };

  const exportToWord = () => {
    if (!previewRef.current || !sheet) return;
    const content = previewRef.current.innerHTML;
    const header = `<html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'><head><meta charset='utf-8'><style>body{font-family:Arial;font-size:11pt}table{border-collapse:collapse;width:100%;border:1px solid black}th,td{border:1px solid black;padding:6px}</style></head><body>${content}</body></html>`;
    const blob = new Blob(['\ufeff', header], { type: 'application/msword' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `CEB_${sheet.title}.doc`;
    link.click();
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      {saveSuccess && (
        <div className="fixed top-20 right-4 z-[100] bg-emerald-600 text-white px-6 py-4 rounded-2xl shadow-2xl flex items-center space-x-3 animate-bounce">
          <i className="fas fa-check-circle text-xl"></i>
          <span className="font-bold">Fiche archivée !</span>
        </div>
      )}

      {pdfLoading && (
        <div className="fixed inset-0 z-[200] bg-slate-900/70 backdrop-blur-md flex items-center justify-center">
          <div className="bg-white p-12 rounded-[3rem] shadow-2xl flex flex-col items-center space-y-6 border-b-8 border-indigo-600">
            <div className="w-20 h-20 border-8 border-indigo-100 border-t-indigo-600 rounded-full animate-spin"></div>
            <div className="text-center">
               <p className="font-black text-slate-900 uppercase tracking-widest text-sm mb-2">Finalisation du Document</p>
               <p className="text-xs text-slate-400 font-bold uppercase">Format A4 Officiel • Haute Résolution</p>
            </div>
          </div>
        </div>
      )}

      <div className="flex flex-col lg:flex-row gap-10">
        <div className="lg:w-[380px] no-print shrink-0">
          <div className="bg-white border border-slate-200 rounded-[2.5rem] p-8 shadow-xl sticky top-24">
            <div className="flex items-center justify-between mb-8">
              <div className="flex flex-col">
                <h2 className="text-2xl font-black text-slate-900 leading-tight tracking-tight">Configuration</h2>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Éditeur Curriculaire</p>
              </div>
              <div className="w-12 h-12 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600 shadow-inner">
                <i className="fas fa-book-open text-xl"></i>
              </div>
            </div>

            <div className="space-y-6">
              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-3 tracking-widest">Type de document</label>
                <div className="grid grid-cols-3 gap-2">
                   {[
                     { id: SheetType.LESSON, label: 'Leçon', icon: 'chalkboard' },
                     { id: SheetType.EXERCISE, label: 'TD/Exos', icon: 'file-pen' },
                     { id: SheetType.EVALUATION, label: 'Éval.', icon: 'award' }
                   ].map(type => (
                     <button 
                      key={type.id}
                      onClick={() => setFormData({...formData, type: type.id as SheetType})}
                      className={`flex flex-col items-center py-4 rounded-2xl border-2 transition-all ${formData.type === type.id ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl scale-105' : 'bg-slate-50 border-slate-100 text-slate-500 hover:border-indigo-200'}`}
