                      className={`flex items-center px-4 py-2 rounded-xl border-2 transition-all font-bold text-xs ${formData.languages.includes(lang.id) ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-slate-50 border-slate-100 text-slate-500 hover:border-indigo-200'}`}
