  const toggleLanguage = (lang: string) => {
    setFormData(prev => {
      const current = prev.languages;
      if (current.includes(lang)) {
        if (current.length === 1) return prev;
        return { ...prev, languages: current.filter(l => l !== lang) };
      }
      return { ...prev, languages: [...current, lang] };
