        html2canvas: { 
          scale: 3, // Augmentation de l'échelle pour une netteté maximale des polices
          useCORS: true, 
          letterRendering: true, // Améliore le rendu des caractères individuels
          logging: false,
          width: 794, // Largeur fixe correspondant à 210mm à 96dpi
          height: 1123, // Hauteur fixe correspondant à 297mm à 96dpi
          windowWidth: 794
        },
        jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait', compress: true },
        pagebreak: { mode: 'avoid-all' }
      };

      const html2pdfLib = (window as any).html2pdf;
      if (typeof html2pdfLib === 'function') {
        // Logique de centrage : margin 0 + format a4 assure que l'élément 210x297mm remplit exactement la page
        await html2pdfLib().set(opt).from(element).toPdf().get('pdf').then((pdf: any) => {
           // On peut ajouter des métadonnées ici si besoin
        }).save();
      } else {
        throw new Error("html2pdf non disponible.");
      }
    } catch (err) {
      console.error(err);
      alert("Échec de l'export haute résolution. Utilisez l'impression système (Ctrl+P) et 'Enregistrer au format PDF'.");
    } finally {
      setPdfLoading(false);
    }
  };

  const exportToWord = () => {
    if (!previewRef.current || !sheet) return;
    const content = previewRef.current.innerHTML;
    const header = `<html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'><head><meta charset='utf-8'><style>body{font-family:Arial;font-size:11pt}table{border-collapse:collapse;width:100%;border:1px solid black}th,td{border:1px solid black;padding:6px}</style></head><body>${content}</body></html>`;
