            vertical-align: top;
          }
          .font-black { font-weight: bold; }
          .uppercase { text-transform: uppercase; }
          .underline { text-decoration: underline; }
          .italic { font-style: italic; }
          .text-center { text-align: center; }
          .bg-slate-50 { background-color: #f1f5f9; }
          .bg-slate-900 { background-color: #0f172a; color: #ffffff; }
          h1 { font-size: 12pt; margin: 0; }
          p { margin: 2pt 0; }
          /* Ensure the container is ignored but content is kept */
          .sheet-container { 
            width: 100% !important; 
            height: auto !important; 
            padding: 0 !important;
            margin: 0 !important;
          }
          /* Fix for hidden elements in print */
          .no-print { display: none; }
        </style>
      </head>
      <body>
        ${content}
      </body>
      </html>`;

    // We use application/msword for best compatibility when serving HTML as a Word document
    const blob = new Blob(['\ufeff', htmlHeader], { type: 'application/msword' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');

    // Using .doc instead of .docx for HTML-based Word files provides much better cross-version stability
    // and avoids the "File Corrupt" warning in many Word versions.
    link.href = url;
    link.download = `Fiche_CEB_${sheet.gradeLevel}_${sheet.title.replace(/\s+/g, '_')}.doc`;
    link.click();

    setTimeout(() => URL.revokeObjectURL(url), 200);
  };

  const containsArabic = (text: string) => /[\u0600-\u06FF]/.test(text || '');
