                              <textarea className="bg-slate-50 rounded-xl p-3 text-xs min-h-[100px] outline-none" value={step.studentActivity} onChange={e => { const s = [...sheet.steps]; s[idx].studentActivity = e.target.value; setSheet({...sheet, steps: s}); }} />
