              <div className="bg-slate-200 rounded-[3rem] p-4 flex justify-center shadow-inner overflow-auto max-h-[900px]">
                {viewMode === 'edit' ? (
                  <div className="bg-white p-10 w-full rounded-[2.5rem] shadow-xl space-y-8" dir={isArabic ? 'rtl' : 'ltr'}>
